using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests
    {
        private SchoolContext CreateContextWithStudents()
        {
            var context = TestDbContextFactory.Create();
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2019, 9, 1) },
                new Student { ID = 3, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            context.SaveChanges();
            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortsByNameDescending()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Barzdukas", model[0].LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Barzdukas", model[0].LastName);
        }

        [Fact]
        public void Index_FiltersStudentsBySearchString()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alex", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchStringResetsPage()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alex", 3) as ViewResult;

            // When searchString is provided, page resets to 1
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_UsesCurrentFilterWhenSearchStringIsNull()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Alex", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            var context = CreateContextWithStudents();
            // Add enrollment data for Include to work
            context.Courses.Add(new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 });
            context.SaveChanges();
            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 1, Grade = Grade.A });
            context.SaveChanges();

            var controller = new StudentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var context = TestDbContextFactory.Create();
            var controller = new StudentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var context = TestDbContextFactory.Create();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(context.Students);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var context = TestDbContextFactory.Create();
            var controller = new StudentsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                LastName = "",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Empty(context.Students);
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var context = TestDbContextFactory.Create();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_EnrollmentDateOutOfRange_ReturnsView()
        {
            var context = TestDbContextFactory.Create();
            var controller = new StudentsController(context);
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenIdIsNull()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithStudent()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);
            var student = new Student
            {
                ID = 1,
                LastName = "Updated",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            // Detach existing tracked entity
            var existing = context.Students.Find(1);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var context = CreateContextWithStudents();
            var controller = new StudentsController(context);
            var student = new Student
            {
                ID = 1,
                LastName = "Updated",
                FirstMidName = "Carson",
                EnrollmentDate = default(DateTime)
            };

