using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private SchoolContext CreateContextWithData()
        {
            var context = TestDbContextFactory.Create();
            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000m, StartDate = new DateTime(2020, 1, 1) };
            context.Departments.Add(dept);
            context.SaveChanges();
            context.Courses.AddRange(
                new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = 1 }
            );
            context.SaveChanges();
            return context;
        }

        private CoursesController CreateController(SchoolContext context)
        {
            var env = new Mock<IWebHostEnvironment>();
            env.Setup(e => e.WebRootPath).Returns("/tmp/wwwroot");
            env.Setup(e => e.ContentRootPath).Returns("/tmp");
            var logger = new Mock<ILogger<CoursesController>>();
            return new CoursesController(context, env.Object, logger.Object);
        }

        [Fact]
        public void Index_ReturnsViewResult_WithCourseList()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            var course = new Course { CourseID = 1003, Title = "Biology", Credits = 3, DepartmentID = 1 };

            var result = controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1003, Title = "", Credits = 3, DepartmentID = 1 };

            var result = controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_WithInvalidFileExtension_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            var course = new Course { CourseID = 1003, Title = "Biology", Credits = 3, DepartmentID = 1 };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.exe");
            fileMock.Setup(f => f.Length).Returns(1024);

            var result = controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            var course = new Course { CourseID = 1003, Title = "Biology", Credits = 3, DepartmentID = 1 };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenCourseDoesNotExist()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithCourse()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Edit(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            var course = new Course { CourseID = 1001, Title = "Advanced Chemistry", Credits = 4, DepartmentID = 1 };

            var existing = context.Courses.Find(1001);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1001, Title = "", Credits = 4, DepartmentID = 1 };

            var result = controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_WithInvalidFileExtension_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);
            var course = new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("bad.txt");
            fileMock.Setup(f => f.Length).Returns(1024);

            var existing = context.Courses.Find(1001);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithCourse()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Delete(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.DeleteConfirmed(1001) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(context.Courses);
        }
    }
}

