using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private SchoolContext CreateContextWithData()
        {
            var context = TestDbContextFactory.Create();

            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000m, StartDate = new DateTime(2020, 1, 1) };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course1 = new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var course2 = new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = 1 };
            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2010, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 1001 });
            context.SaveChanges();

            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            var context = CreateContextWithData();
            // Add enrollment
            context.Students.Add(new Student { ID = 10, LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = new DateTime(2020, 9, 1) });
            context.SaveChanges();
            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A });
            context.SaveChanges();

            var controller = new InstructorsController(context);

            var result = controller.Index(1, 1001) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithInstructor()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithAssignedCourses()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = new DateTime(2015, 1, 1)
            };

            var result = controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane",
                HireDate = new DateTime(2015, 1, 1)
            };

            var result = controller.Create(instructor, new[] { "1001", "1002" }) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var created = context.Instructors.First(i => i.LastName == "Doe");
            Assert.Equal(2, context.CourseAssignments.Count(ca => ca.InstructorID == created.ID));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                LastName = "",
                FirstMidName = "Jane",
                HireDate = new DateTime(2015, 1, 1)
            };

            var result = controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithInstructor()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithInstructor()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            var context = CreateContextWithData();
            // Add office assignment
            context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 101" });
            context.SaveChanges();

            var controller = new InstructorsController(context);

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            var context = CreateContextWithData();
            // Set instructor as department admin
            var dept = context.Departments.Find(1);
            dept.InstructorID = 1;
            context.SaveChanges();

            // Add office assignment (required by DeleteConfirmed's Include)
            context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 101" });
            context.SaveChanges();

            var controller = new InstructorsController(context);

            controller.DeleteConfirmed(1);

            var updatedDept = context.Departments.Find(1);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

