using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests
    {
        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "42", EntityOperation.UPDATE);

            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "user1");

            var notification = service.ReceiveNotification();
            Assert.Contains("New", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "user1");

            var notification = service.ReceiveNotification();
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            var service = new NotificationService();

            service.SendNotification("Course", "101", "Chemistry", EntityOperation.DELETE, "user1");

            var notification = service.ReceiveNotification();
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            var service = new NotificationService();

            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var service = new NotificationService();

            // Drain any existing messages from static queue
            while (service.ReceiveNotification() != null) { }

            var notification = service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var service = new NotificationService();
            var before = DateTime.Now;

            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

            var notification = service.ReceiveNotification();
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var service = new NotificationService();

            // MarkAsRead is a no-op for in-memory but should not throw
            var exception = Record.Exception(() => service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();

            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_MultipleMessages_MaintainsOrder()
        {
            var service = new NotificationService();

            service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
            service.SendNotification("C", "3", "Third", EntityOperation.DELETE);

            var first = service.ReceiveNotification();
            var second = service.ReceiveNotification();
            var third = service.ReceiveNotification();

            // Due to static queue, we check entity types
            Assert.NotNull(first);
            Assert.NotNull(second);
            Assert.NotNull(third);
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var items = Enumerable.Range(1, 25).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var items = Enumerable.Range(1, 25).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 2, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(2, page.PageIndex);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var items = Enumerable.Range(1, 25).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 3, 10);

            Assert.Equal(5, page.Count);
            Assert.Equal(3, page.PageIndex);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 2, 10);

            Assert.True(page.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.True(page.HasNextPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 2, 10);

            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<Student>
            {
                new Student { ID = 1, LastName = "A", FirstMidName = "B", EnrollmentDate = DateTime.Today }
            };

            var page = new PaginatedList<Student>(items, 15, 2, 10);

            Assert.Equal(2, page.PageIndex);
            Assert.Equal(2, page.TotalPages);
            Assert.Single(page);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var items = Enumerable.Empty<Student>().AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.Empty(page);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(0, page.TotalPages);
        }
    }
