            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            var context = CreateContextWithData();
            // Add enrollment
            context.Students.Add(new Student { ID = 10, LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = new DateTime(2020, 9, 1) });
            context.SaveChanges();
            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A });
