{"file_text": "using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var items = Enumerable.Range(1, 25).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(3, page.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var items = Enumerable.Range(1, 25).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 2, 10);

            Assert.Equal(10, page.Count);
            Assert.Equal(2, page.PageIndex);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var items = Enumerable.Range(1, 25).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 3, 10);

            Assert.Equal(5, page.Count);
            Assert.Equal(3, page.PageIndex);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.False(page.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 2, 10);

            Assert.True(page.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_FirstPage_ReturnsTrue()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.True(page.HasNextPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var items = Enumerable.Range(1, 20).Select(i => new Student
            {
                ID = i,
                LastName = $"Student{i}",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Today
            }).AsQueryable();

            var page = PaginatedList<Student>.Create(items, 2, 10);

            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void Constructor_SetsProperties()
        {
            var items = new List<Student>
            {
                new Student { ID = 1, LastName = "A", FirstMidName = "B", EnrollmentDate = DateTime.Today }
            };

            var page = new PaginatedList<Student>(items, 15, 2, 10);

            Assert.Equal(2, page.PageIndex);
            Assert.Equal(2, page.TotalPages);
            Assert.Single(page);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var items = Enumerable.Empty<Student>().AsQueryable();

            var page = PaginatedList<Student>.Create(items, 1, 10);

            Assert.Empty(page);
            Assert.Equal(1, page.PageIndex);
            Assert.Equal(0, page.TotalPages);
        }
    }
}
