{"file_text": "using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var context = TestDbContextFactory.Create();
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("TestLast", retrieved.LastName);
            Assert.Equal("TestFirst", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var context = TestDbContextFactory.Create();
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Dept", Budget = 1000, StartDate = DateTime.Today });
            context.SaveChanges();
            var course = new Course { CourseID = 101, Title = "Test Course", Credits = 3, DepartmentID = 1 };

            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.First();
            Assert.Equal("Test Course", retrieved.Title);
            Assert.Equal(3, retrieved.Credits);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var context = TestDbContextFactory.Create();
            var dept = new Department { Name = "Computer Science", Budget = 50000m, StartDate = new DateTime(2020, 1, 1) };

            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments.First();
            Assert.Equal("Computer Science", retrieved.Name);
            Assert.Equal(50000m, retrieved.Budget);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var context = TestDbContextFactory.Create();
            var instructor = new Instructor
            {
                LastName = "InstructorLast",
                FirstMidName = "InstructorFirst",
                HireDate = new DateTime(2015, 6, 1)
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.First();
            Assert.Equal("InstructorLast", retrieved.LastName);
        }

        [Fact]
        public void CanAddEnrollment_WithRelationships()
        {
            var context = TestDbContextFactory.Create();
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Dept", Budget = 1000, StartDate = DateTime.Today });
            context.SaveChanges();
            context.Courses.Add(new Course { CourseID = 101, Title = "Course", Credits = 3, DepartmentID = 1 });
            context.Students.Add(new Student { ID = 1, LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Today });
            context.SaveChanges();

            context.Enrollments.Add(new Enrollment { CourseID = 101, StudentID = 1, Grade = Grade.A });
            context.SaveChanges();

            var enrollment = context.Enrollments.Include(e => e.Course).Include(e => e.Student).First();
            Assert.Equal("Course", enrollment.Course.Title);
            Assert.Equal("S", enrollment.Student.LastName);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var context = TestDbContextFactory.Create();
            context.Departments.Add(new Department { DepartmentID = 1, Name = "Dept", Budget = 1000, StartDate = DateTime.Today });
            context.SaveChanges();
            context.Courses.Add(new Course { CourseID = 101, Title = "Course", Credits = 3, DepartmentID = 1 });
            context.Instructors.Add(new Instructor { ID = 1, LastName = "I", FirstMidName = "J", HireDate = DateTime.Today });
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { CourseID = 101, InstructorID = 1 });
            context.SaveChanges();

            var ca = context.CourseAssignments.First();
            Assert.Equal(101, ca.CourseID);
            Assert.Equal(1, ca.InstructorID);
        }

        [Fact]
        public void OfficeAssignment_OneToOne_WithInstructor()
        {
            var context = TestDbContextFactory.Create();
            context.Instructors.Add(new Instructor { ID = 1, LastName = "I", FirstMidName = "J", HireDate = DateTime.Today });
            context.SaveChanges();

            context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 101" });
            context.SaveChanges();

            var office = context.OfficeAssignments.Include(o => o.Instructor).First();
            Assert.Equal("Room 101", office.Location);
            Assert.Equal("I", office.Instructor.LastName);
        }

        [Fact]
        public void Person_FullName_ReturnsCombinedName()
        {
            var student = new Student { LastName = "Doe", FirstMidName = "John", EnrollmentDate = DateTime.Today };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void CanAddNotification()
        {
            var context = TestDbContextFactory.Create();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("Test notification", retrieved.Message);
        }
    }
}
