using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private SchoolContext CreateContextWithData()
        {
            var context = TestDbContextFactory.Create();
            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000m, StartDate = new DateTime(2020, 1, 1) };
            context.Departments.Add(dept);
            context.SaveChanges();
            context.Courses.AddRange(
                new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = 1 }
            );
            context.SaveChanges();
            return context;
        }

        private CoursesController CreateController(SchoolContext context)
        {
            var env = new Mock<IWebHostEnvironment>();
            env.Setup(e => e.WebRootPath).Returns("/tmp/wwwroot");
            env.Setup(e => e.ContentRootPath).Returns("/tmp");
            var logger = new Mock<ILogger<CoursesController>>();
            return new CoursesController(context, env.Object, logger.Object);
        }

        [Fact]
        public void Index_ReturnsViewResult_WithCourseList()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Details(1001) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var context = CreateContextWithData();
            var controller = CreateController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var context = CreateContextWithData();
