namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private SchoolContext CreateContextWithData()
        {
            var context = TestDbContextFactory.Create();
            context.Instructors.Add(new Instructor { ID = 1, LastName = "Smith", FirstMidName = "John", HireDate = new DateTime(2010, 1, 1) });
            context.SaveChanges();
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000m, StartDate = new DateTime(2020, 1, 1), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Science", Budget = 80000m, StartDate = new DateTime(2019, 1, 1) }
            );
            context.SaveChanges();
            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithDepartmentList()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithDepartment()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);
            var dept = new Department { Name = "Math", Budget = 50000m, StartDate = new DateTime(2021, 1, 1), InstructorID = 1 };

            var result = controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { Name = "", Budget = 50000m, StartDate = new DateTime(2021, 1, 1) };

            var result = controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithDepartment()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);
            var dept = new Department { DepartmentID = 1, Name = "Updated Engineering", Budget = 120000m, StartDate = new DateTime(2020, 1, 1), InstructorID = 1 };

            var existing = context.Departments.Find(1);
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = controller.Edit(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department { DepartmentID = 1, Name = "", Budget = 120000m, StartDate = new DateTime(2020, 1, 1) };

            var result = controller.Edit(dept) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithDepartment()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            var context = CreateContextWithData();
            var controller = new DepartmentsController(context);

            var result = controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(context.Departments);
        }
    }
}

