using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private SchoolContext CreateContextWithData()
        {
            var context = TestDbContextFactory.Create();

            var dept = new Department { DepartmentID = 1, Name = "Engineering", Budget = 100000m, StartDate = new DateTime(2020, 1, 1) };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course1 = new Course { CourseID = 1001, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
            var course2 = new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = 1 };
            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = new DateTime(2010, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 1001 });
            context.SaveChanges();

            return context;
        }

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var context = CreateContextWithData();
            var controller = new InstructorsController(context);

            var result = controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_ShowsEnrollments()
        {
            var context = CreateContextWithData();
            // Add enrollment
            context.Students.Add(new Student { ID = 10, LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = new DateTime(2020, 9, 1) });
            context.SaveChanges();
            context.Enrollments.Add(new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A });
            context.SaveChanges();

            var controller = new InstructorsController(context);

            var result = controller.Index(1, 1001) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
