            var controller = new HomeController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void About_ReturnsViewResult_WithEnrollmentDateGroups()
        {
            var context = TestDbContextFactory.Create();
            context.Students.AddRange(
                new Student { ID = 1, LastName = "A", FirstMidName = "B", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 2, LastName = "C", FirstMidName = "D", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { ID = 3, LastName = "E", FirstMidName = "F", EnrollmentDate = new DateTime(2021, 9, 1) }
            );
            context.SaveChanges();

            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(result.Model);
            Assert.Equal(2, model.Count);
            Assert.Contains(model, g => g.StudentCount == 2);
            Assert.Contains(model, g => g.StudentCount == 1);
        }

        [Fact]
        public void Contact_ReturnsViewResult_WithMessage()
        {
            var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Error() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewResult_WithMessage()
        {
            var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

